// Evaluate staleness of each data source
const now = new Date();
const STALE_THRESHOLD_HOURS = 24;

function checkStaleness(lastDate, label) {
  if (!lastDate) return { table: label, status: 'ERROR', message: 'No data found', hoursAgo: null };
  const last = new Date(lastDate);
  const hoursAgo = Math.round((now - last) / (1000 * 60 * 60) * 10) / 10;
  const isStale = hoursAgo > STALE_THRESHOLD_HOURS;
  return {
    table: label,
    status: isStale ? 'STALE' : 'OK',
    message: isStale ? `Data is ${hoursAgo}h old (threshold: ${STALE_THRESHOLD_HOURS}h)` : 'Data is fresh',
    hoursAgo
  };
}

// Get data from parallel DB checks
const competitorItems = $('Sync Competitor Cache').all();
const oodaItems = $('Sync OODA Data').all();
const intelItems = $('Sync Intelligence Log').all();

const oodaData = oodaItems[0]?.json || {};
const intelData = intelItems[0]?.json || {};

const checks = [
  { table: 'gda_competitor_cache', status: 'OK', message: 'Stale entries purged successfully' },
  checkStaleness(oodaData.last_ooda, 'gda_ooda_loops'),
  checkStaleness(intelData.last_intel, 'gda_intelligence_log')
];

const issues = checks.filter(c => c.status !== 'OK');

return [{
  json: {
    timestamp: now.toISOString(),
    overall_status: issues.length > 0 ? 'ISSUES_DETECTED' : 'HEALTHY',
    issue_count: issues.length,
    checks,
    ooda_count: oodaData.ooda_count || 0,
    intel_count: intelData.intel_count || 0
  }
}];
